// Floyd-Warshall algorithm with OpenMP Target Offload

#include <cstdio>
#include <omp.h>

int main() {
    const int N = 4;
    int dist[N][N] = {
        {0, 3, 999, 7},
        {8, 0, 2, 999},
        {5, 999, 0, 1},
        {2, 999, 999, 0}
    };

    for (int k = 0; k < N; ++k) {
        #pragma omp target teams distribute parallel for collapse(2) map(tofrom: dist)
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                int new_dist = dist[i][k] + dist[k][j];
                if (new_dist < dist[i][j]) {
                    dist[i][j] = new_dist;
                }
            }
        }
    }

    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            if (dist[i][j] == 999)
                printf("%4s", "INF");
            else
                printf("%4d", dist[i][j]);
        }
        printf("\n");
    }

    return 0;
}
